{"code":"import json

def get_json_from_tool_output(output_string):
    # The JSON part is usually a list of dictionaries. Find the first '[' and last ']'.
    start_index = output_string.find('[')
    end_index = output_string.rfind(']')

    if start_index != -1 and end_index != -1 and start_index < end_index:
        json_candidate = output_string[start_index : end_index + 1]
        try:
            return json.loads(json_candidate)
        except json.JSONDecodeError:
            # If it's not valid JSON, return None
            return None
    return None

